{
  "name": "Neural Architecture 3D Explorer",
  "description": "A 3D interactive visualization of 7B Transformer and Wav2Vec 2.0 architectures, breaking down matrix multiplications, parameter counts, and data flow layer by layer."
}

export enum ModelType {
  TRANSFORMER_7B = 'TRANSFORMER_7B',
  WAV2VEC_100M = 'WAV2VEC_100M',
}

export interface MathFormula {
  label: string;
  latex: string;
  description: string;
  paramCount?: string;
  shapeCheck?: string;
}

export interface ProcessingStage {
  id: string;
  title: string;
  type: 'input' | 'attention' | 'mlp' | 'norm' | 'cnn' | 'output';
  description: string;
  formulas: MathFormula[];
  position: [number, number, number]; // 3D position
  dimensions: [number, number, number]; // 3D size
  color: string;
}

export interface ModelConfig {
  id: ModelType;
  name: string;
  description: string;
  specs: {
    hiddenSize: number;
    layers: number;
    heads: number;
    ffnSize: number;
    vocabSize?: number;
    convLayers?: number;
    paramsPerLayer: string;
    totalParams: string;
    vramTraining: string;
  };
  stages: ProcessingStage[];
}

import React from 'react';
import { ProcessingStage, MathFormula } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

interface MathPanelProps {
  stage: ProcessingStage | null;
}

const FormulaItem = ({ formula }: { formula: MathFormula }) => (
  <div className="mb-4 last:mb-0 p-3 bg-slate-50 rounded-lg border border-slate-100">
    <div className="flex justify-between items-baseline mb-1">
      <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">{formula.label}</span>
      <span className="text-xs text-slate-400 italic font-mono">{formula.description}</span>
    </div>
    <div className="font-mono text-slate-800 text-sm md:text-base bg-white p-2 rounded border border-slate-200 shadow-sm overflow-x-auto">
      {formula.latex}
    </div>
  </div>
);

export const MathPanel: React.FC<MathPanelProps> = ({ stage }) => {
  return (
    <div className="absolute bottom-6 right-6 w-full max-w-md z-10 pointer-events-none">
       <AnimatePresence mode="wait">
        {stage ? (
          <motion.div
            key={stage.id}
            initial={{ opacity: 0, y: 20, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 10, scale: 0.95 }}
            transition={{ duration: 0.3 }}
            className="bg-white/90 backdrop-blur-md rounded-xl shadow-xl border border-slate-200 overflow-hidden pointer-events-auto"
          >
            <div className="p-4 border-b border-slate-100 flex items-center justify-between">
              <div>
                <h3 className="font-semibold text-slate-800">{stage.title}</h3>
                <p className="text-xs text-slate-500 uppercase tracking-widest">{stage.type}</p>
              </div>
              <div 
                className="w-4 h-4 rounded-full shadow-inner" 
                style={{ backgroundColor: stage.color }}
              />
            </div>

            <div className="p-4 max-h-[60vh] overflow-y-auto">
              <p className="text-sm text-slate-600 mb-4 leading-relaxed">
                {stage.description}
              </p>

              {stage.formulas.length > 0 && (
                <div className="space-y-2">
                  {stage.formulas.map((f, i) => (
                    <FormulaItem key={i} formula={f} />
                  ))}
                </div>
              )}
            </div>
          </motion.div>
        ) : (
          <motion.div
            key="empty"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="bg-white/80 backdrop-blur p-4 rounded-xl shadow border border-slate-200 text-slate-500 text-sm text-center italic pointer-events-auto"
          >
            Hover over a layer block to see details.
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

import React, { useRef, useState, useMemo } from 'react';
import { Canvas, useFrame, ThreeEvent } from '@react-three/fiber';
import { OrbitControls, Text, Float, Environment, ContactShadows, useCursor } from '@react-three/drei';
import * as THREE from 'three';
import { ModelConfig, ProcessingStage } from '../types';

// Helper for pastel material with soft shading
const PastelMaterial = ({ color, hovered, active }: { color: string; hovered: boolean; active: boolean }) => {
  return (
    <meshPhysicalMaterial
      color={active ? '#60A5FA' : (hovered ? new THREE.Color(color).offsetHSL(0, 0, -0.1) : color)}
      roughness={0.2}
      metalness={0.1}
      transmission={0.1} // slight glass effect
      thickness={1}
      clearcoat={0.5}
      transparent
      opacity={0.95}
    />
  );
};

const LayerBlock = ({ 
  stage, 
  onClick, 
  onPointerOver, 
  onPointerOut,
  isActive 
}: { 
  stage: ProcessingStage; 
  onClick: () => void;
  onPointerOver: (e: ThreeEvent<PointerEvent>) => void;
  onPointerOut: (e: ThreeEvent<PointerEvent>) => void;
  isActive: boolean;
}) => {
  const [hovered, setHover] = useState(false);
  const meshRef = useRef<THREE.Mesh>(null);

  useCursor(hovered);

  useFrame((state) => {
    if (meshRef.current && hovered) {
      meshRef.current.rotation.y = THREE.MathUtils.lerp(meshRef.current.rotation.y, 0.1, 0.1);
    } else if (meshRef.current) {
      meshRef.current.rotation.y = THREE.MathUtils.lerp(meshRef.current.rotation.y, 0, 0.1);
    }
  });

  const handleOver = (e: ThreeEvent<PointerEvent>) => {
    e.stopPropagation();
    setHover(true);
    onPointerOver(e);
  };

  const handleOut = (e: ThreeEvent<PointerEvent>) => {
    setHover(false);
    onPointerOut(e);
  };

  return (
    <group position={new THREE.Vector3(...stage.position)}>
      {/* Connector Line to prev layer (visual only) */}
      {stage.position[1] > 0 && (
         <mesh position={[0, -0.75, 0]}>
           <cylinderGeometry args={[0.05, 0.05, 1.5, 8]} />
           <meshStandardMaterial color="#CBD5E0" />
         </mesh>
      )}

      <Float speed={2} rotationIntensity={0.05} floatIntensity={0.1}>
        <mesh
          ref={meshRef}
          onClick={(e) => { e.stopPropagation(); onClick(); }}
          onPointerOver={handleOver}
          onPointerOut={handleOut}
        >
          <boxGeometry args={[stage.dimensions[0], stage.dimensions[1], stage.dimensions[2]]} />
          <PastelMaterial color={stage.color} hovered={hovered} active={isActive} />

          {/* Edges */}
          <lineSegments>
            <edgesGeometry args={[new THREE.BoxGeometry(stage.dimensions[0], stage.dimensions[1], stage.dimensions[2])]} />
            <lineBasicMaterial color={isActive ? "white" : "grey"} transparent opacity={0.3} />
          </lineSegments>
        </mesh>
      </Float>

      {/* Label */}
      <group position={[stage.dimensions[0]/2 + 0.5, 0, 0]}>
        <Text
          fontSize={0.3}
          color="#4A5568"
          anchorX="left"
          anchorY="middle"
          font="https://fonts.gstatic.com/s/inter/v12/UcCO3FwrK3iLTeHuS_fvQtMwCp50KnMw2boKoduKmMEVuLyfAZ9hjp-Ek-_EeA.woff"
        >
          {stage.title}
        </Text>
        <Text
          position={[0, -0.25, 0]}
          fontSize={0.15}
          color="#718096"
          anchorX="left"
          anchorY="middle"
        >
          {stage.formulas[0]?.latex || ""}
        </Text>
      </group>
    </group>
  );
};

interface VisualizerProps {
  model: ModelConfig;
  activeStageId: string | null;
  onStageSelect: (stage: ProcessingStage | null) => void;
}

export const Visualizer3D: React.FC<VisualizerProps> = ({ model, activeStageId, onStageSelect }) => {
  // Center camera based on model height
  const centerY = useMemo(() => {
    if (model.stages.length === 0) return 0;
    const last = model.stages[model.stages.length - 1];
    return last.position[1] / 2;
  }, [model]);

  return (
    <div className="w-full h-full bg-slate-50 cursor-move relative">
       <div className="absolute top-4 left-1/2 -translate-x-1/2 z-10 bg-white/50 backdrop-blur px-4 py-1 rounded-full text-xs text-slate-500 pointer-events-none">
          Drag to rotate • Scroll to zoom • Click blocks for details
       </div>

      <Canvas shadows camera={{ position: [8, centerY + 2, 12], fov: 45 }}>
        <fog attach="fog" args={['#F8FAFC', 10, 40]} />
        <ambientLight intensity={0.7} />
        <spotLight position={[10, 20, 10]} angle={0.3} penumbra={1} intensity={1} castShadow />
        <pointLight position={[-10, 10, -10]} intensity={0.5} color="#A7C7E7" />

        <Environment preset="city" />

        <group position={[0, -centerY + 2, 0]}>
          {model.stages.map((stage) => (
            <LayerBlock
              key={stage.id}
              stage={stage}
              isActive={activeStageId === stage.id}
              onClick={() => onStageSelect(stage)}
              onPointerOver={() => onStageSelect(stage)}
              onPointerOut={() => onStageSelect(null)}
            />
          ))}
        </group>

        <ContactShadows opacity={0.4} scale={30} blur={2} far={4.5} />
        <OrbitControls 
          enablePan={true} 
          minPolarAngle={0} 
          maxPolarAngle={Math.PI / 1.5}
          target={[0, centerY, 0]}
        />
      </Canvas>
    </div>
  );
};

import React, { useState } from 'react';
import { ModelType, ProcessingStage } from './types';
import { MODELS } from './constants';
import { Visualizer3D } from './components/Visualizer3D';
import { MathPanel } from './components/MathPanel';
import { motion } from 'framer-motion';

const SidebarItem = ({ 
  label, 
  value, 
  sub 
}: { 
  label: string; 
  value: string | number; 
  sub?: string 
}) => (
  <div className="flex flex-col py-2 border-b border-slate-100 last:border-0">
    <span className="text-xs text-slate-400 uppercase tracking-wider mb-0.5">{label}</span>
    <span className="text-sm font-medium text-slate-700 font-mono">{value}</span>
    {sub && <span className="text-[10px] text-slate-400">{sub}</span>}
  </div>
);

const App = () => {
  const [selectedModelType, setSelectedModelType] = useState<ModelType>(ModelType.TRANSFORMER_7B);
  const [activeStage, setActiveStage] = useState<ProcessingStage | null>(null);

  const currentModel = MODELS[selectedModelType];

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-slate-50 text-slate-800">

      {/* Sidebar Panel */}
      <div className="w-80 md:w-96 flex-shrink-0 bg-white border-r border-slate-200 flex flex-col z-20 shadow-lg">
        {/* Header */}
        <div className="p-6 border-b border-slate-100">
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-slate-700 to-slate-500">
            NeuroVis 3D
          </h1>
          <p className="text-xs text-slate-400 mt-1">Deep Learning Architecture Explorer</p>
        </div>

        {/* Model Selector */}
        <div className="p-4 bg-slate-50/50">
          <div className="flex bg-slate-200 p-1 rounded-lg">
            <button
              onClick={() => setSelectedModelType(ModelType.TRANSFORMER_7B)}
              className={`flex-1 py-2 text-xs font-semibold rounded-md transition-all ${
                selectedModelType === ModelType.TRANSFORMER_7B
                  ? 'bg-white text-slate-800 shadow-sm'
                  : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              7B Transformer
            </button>
            <button
              onClick={() => setSelectedModelType(ModelType.WAV2VEC_100M)}
              className={`flex-1 py-2 text-xs font-semibold rounded-md transition-all ${
                selectedModelType === ModelType.WAV2VEC_100M
                  ? 'bg-white text-slate-800 shadow-sm'
                  : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              Wav2Vec 2.0
            </button>
          </div>
        </div>

        {/* Model Stats */}
        <div className="flex-1 overflow-y-auto p-6 scrollbar-hide">
          <motion.div
            key={selectedModelType}
            initial={{ opacity: 0, x: -10 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.3 }}
          >
            <div className="mb-6">
              <h2 className="text-lg font-semibold text-slate-800 mb-2">{currentModel.name}</h2>
              <p className="text-sm text-slate-500 leading-relaxed">
                {currentModel.description}
              </p>
            </div>

            <div className="bg-slate-50 rounded-xl p-4 border border-slate-100 mb-6">
              <h3 className="text-xs font-bold text-slate-800 uppercase mb-3">Training Specs</h3>
              <SidebarItem label="Hidden Size (H)" value={currentModel.specs.hiddenSize} />
              <SidebarItem label="Layers (L)" value={currentModel.specs.layers} />
              <SidebarItem label="Attention Heads" value={currentModel.specs.heads} sub={`Head Dim: ${currentModel.specs.hiddenSize / currentModel.specs.heads}`} />
              <SidebarItem label="FFN / MLP Size" value={currentModel.specs.ffnSize} />
              {currentModel.specs.convLayers && (
                <SidebarItem label="CNN Layers" value={currentModel.specs.convLayers} />
              )}
            </div>

             <div className="bg-slate-50 rounded-xl p-4 border border-slate-100">
              <h3 className="text-xs font-bold text-slate-800 uppercase mb-3">Memory & Params</h3>
              <SidebarItem label="Params / Layer" value={currentModel.specs.paramsPerLayer} />
              <SidebarItem label="Total Params" value={currentModel.specs.totalParams} />
              <SidebarItem label="Est. VRAM (Full Fine-tune)" value={currentModel.specs.vramTraining} />
            </div>
          </motion.div>
        </div>

        {/* Footer */}
        <div className="p-4 border-t border-slate-100 text-[10px] text-slate-400 text-center">
          Interactive WebGL Visualization • React Three Fiber
        </div>
      </div>

      {/* Main 3D Viewport */}
      <div className="flex-1 relative">
        <Visualizer3D 
          model={currentModel} 
          activeStageId={activeStage?.id || null} 
          onStageSelect={setActiveStage}
        />

        {/* Math & Detail Overlay */}
        <MathPanel stage={activeStage} />
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

